## **Node.js/Express with In-Memory Cache**

```javascript
const express = require('express');
const app = express();

// Cache layer with TTL support
class CacheLayer {
  constructor(ttl = 300000) { // 5 minutes default
    this.cache = new Map();
    this.ttl = ttl;
  }

  set(key, value) {
    const expiresAt = Date.now() + this.ttl;
    this.cache.set(key, { value, expiresAt });
  }

  get(key) {
    const item = this.cache.get(key);
    if (!item) return null;

    if (Date.now() > item.expiresAt) {
      this.cache.delete(key);
      return null;
    }
    return item.value;
  }

  invalidate(key) {
    this.cache.delete(key);
  }

  invalidatePattern(pattern) {
    const regex = new RegExp(pattern);
    for (const key of this.cache.keys()) {
      if (regex.test(key)) {
        this.cache.delete(key);
      }
    }
  }
}

const profileCache = new CacheLayer(300000); // 5 minutes

// Cache middleware
function userProfileCache(req, res, next) {
  const userId = req.params.id;
  const cacheKey = `user:${userId}`;

  const cached = profileCache.get(cacheKey);
  if (cached) {
    return res.json({ data: cached, source: 'cache' });
  }

  next();
}

// Get user profile
app.get('/api/users/:id', userProfileCache, (req, res) => {
  const userId = parseInt(req.params.id);
  const cacheKey = `user:${userId}`;

  const user = fetchUserFromDB(userId);
  if (!user) return res.status(404).json({ error: 'Not found' });

  profileCache.set(cacheKey, user);
  res.json({ data: user, source: 'database' });
});

// Update user (invalidate cache)
app.patch('/api/users/:id', (req, res) => {
  const userId = parseInt(req.params.id);
  const cacheKey = `user:${userId}`;

  updateUserInDB(userId, req.body);
  profileCache.invalidate(cacheKey);

  res.json({ message: 'Updated' });
});
```

## **Redis-Based Cache (Production)**

```javascript
const redis = require('redis');
const client = redis.createClient();

const CACHE_TTL = 300; // 5 minutes

async function getUserProfile(userId) {
  const cacheKey = `user:${userId}`;

  // Try cache first
  const cached = await client.get(cacheKey);
  if (cached) {
    return JSON.parse(cached);
  }

  // Fetch from DB
  const user = await db.users.findById(userId);
  if (!user) return null;

  // Store in cache with TTL
  await client.setex(cacheKey, CACHE_TTL, JSON.stringify(user));

  return user;
}

async function updateUserProfile(userId, updates) {
  const cacheKey = `user:${userId}`;

  // Update DB
  const user = await db.users.update(userId, updates);

  // Invalidate cache
  await client.del(cacheKey);

  return user;
}

// Express routes
app.get('/api/users/:id', async (req, res) => {
  const user = await getUserProfile(req.params.id);
  res.json(user);
});

app.patch('/api/users/:id', async (req, res) => {
  const user = await updateUserProfile(req.params.id, req.body);
  res.json(user);
});
```

## **Python/FastAPI Cache**

```python
from fastapi import FastAPI
from functools import lru_cache
from datetime import datetime, timedelta
import asyncio

app = FastAPI()

class CacheStore:
    def __init__(self, ttl_seconds=300):
        self.store = {}
        self.ttl = ttl_seconds

    def get(self, key):
        if key not in self.store:
            return None
        value, expiry = self.store[key]
        if datetime.now() > expiry:
            del self.store[key]
            return None
        return value

    def set(self, key, value):
        expiry = datetime.now() + timedelta(seconds=self.ttl)
        self.store[key] = (value, expiry)

    def invalidate(self, key):
        self.store.pop(key, None)

cache = CacheStore(ttl_seconds=300)

@app.get("/api/users/{user_id}")
async def get_user(user_id: int):
    cache_key = f"user:{user_id}"

    # Try cache
    cached = cache.get(cache_key)
    if cached:
        return {"data": cached, "source": "cache"}

    # Fetch from DB
    user = await fetch_user_from_db(user_id)
    if not user:
        return {"error": "Not found"}, 404

    # Store in cache
    cache.set(cache_key, user)
    return {"data": user, "source": "database"}

@app.patch("/api/users/{user_id}")
async def update_user(user_id: int, updates: dict):
    cache_key = f"user:{user_id}"

    # Update DB
    user = await update_user_in_db(user_id, updates)

    # Invalidate cache
    cache.invalidate(cache_key)

    return {"data": user}
```

**Key features:**
- **TTL expiry** — automatic cache cleanup
- **Pattern-based invalidation** — clear related caches (all users, etc.)
- **Cache-aside pattern** — check cache, fallback to DB, populate cache
- **Manual invalidation** — clear on write operations

